// Pure TypeScript config module with environment variable support
export interface AppConfig {
  server: { host: string; port: number };
  database: { url: string; pool_size: number; timeout_ms: number };
  auth: { secret: string; token_ttl: number };
  logging: { level: string; format: string };
}

function getEnvVar(name: string, defaultValue?: string): string {
  const value = process.env[name];
  if (value === undefined) {
    if (defaultValue !== undefined) {
      return defaultValue;
    }
    throw new Error(`Environment variable ${name} is required but not set`);
  }
  return value;
}

function getEnvNumber(name: string, defaultValue?: number): number {
  const value = process.env[name];
  if (value === undefined) {
    if (defaultValue !== undefined) {
      return defaultValue;
    }
    throw new Error(`Environment variable ${name} is required but not set`);
  }
  const parsed = parseInt(value, 10);
  if (isNaN(parsed)) {
    throw new Error(`Environment variable ${name} must be a valid number, got: ${value}`);
  }
  return parsed;
}

export function loadConfig(): AppConfig {
  return {
    server: {
      host: getEnvVar('SERVER_HOST'),
      port: getEnvNumber('SERVER_PORT'),
    },
    database: {
      url: getEnvVar('DATABASE_URL'),
      pool_size: 10, // Static value as specified
      timeout_ms: 5000, // Static value as specified
    },
    auth: {
      secret: getEnvVar('AUTH_SECRET'),
      token_ttl: 3600, // Static value as specified
    },
    logging: {
      level: getEnvVar('LOG_LEVEL'),
      format: 'json', // Static value as specified
